 *
 * Computes minimax polynomial approximations for sin(x)/x and cos(x)
 * as even polynomials in u = x^2, on domain [0, (pi/4)^2].
 *
 * Q0.32 interpretation: the actual argument x is in [0, pi/4],
 * and u = x^2 is in [0, (pi/4)^2 ≈ 0.617].
 *
 * Output format: one coefficient per line, from constant term (degree 0)
 * to highest degree, each labeled for Python parsing.
 */

prec = 256!;
display = decimal;

/* Domain: u = x^2 for x in [0, pi/4] */
d = [0, (Pi/4)^2];

/* g_sin(u) = sin(sqrt(u))/sqrt(u): smooth, equals 1 at u=0 */
/* Use a small positive lower bound to avoid sqrt(0)/0 in Sollya */
g_sin = sin(sqrt(x))/sqrt(x);

/* g_cos(u) = cos(sqrt(u)): smooth, equals 1 at u=0 */
g_cos = cos(sqrt(x));

/* --- Sin polynomial: degree ${SIN_N_TERMS} in u --- */
print("SIN_COEFFS_BEGIN");
{
    p_sin = fpminimax(g_sin, ${SIN_DEG_LIST}, ${SIN_FMT_LIST}, d, relative);
    e_sin = supnorm(p_sin, g_sin, d, relative, 2^(-53));
    print("SUPNORM_SIN:", e_sin);
${SIN_COEFF_PRINTS}};
print("SIN_COEFFS_END");

/* --- Cos polynomial: degree ${COS_N_TERMS} in u --- */
print("COS_COEFFS_BEGIN");
{
    p_cos = fpminimax(g_cos, ${COS_DEG_LIST}, ${COS_FMT_LIST}, d, relative);
    e_cos = supnorm(p_cos, g_cos, d, relative, 2^(-53));
    print("SUPNORM_COS:", e_cos);
${COS_COEFF_PRINTS}};
print("COS_COEFFS_END");

